      if grid[top][j] == '*' {
        jDone := true;
      } else {
        j := j + 1;
      }
    }
    if jDone {
      topDone := true;
    } else {
      assert forall c | 0 <= c < |grid[top]| :: grid[top][c] != '*';
      top := top + 1;
    }
  }
  if !topDone {
    assert forall r | 0 <= r < |grid| :: forall c | 0 <= c < |grid[r]| :: grid[r][c] != '*';
    assert !HasStar(grid);
    assert false;
    result := []; return;
  }

