      invariant rDone ==> 0 <= r < n && grid[r][left] == '*'
      decreases n - r, !rDone
    {
      if grid[r][left] == '*' {
        rDone := true;
      } else {
        r := r + 1;
      }
    }
    if rDone {
      leftDone := true;
    } else {
      assert forall rr | 0 <= rr < n :: grid[rr][left] != '*';
      left := left + 1;
    }
  }
  if !leftDone {
    forall r | 0 <= r < n
      ensures forall c | 0 <= c < |grid[r]| :: grid[r][c] != '*'
    {
      assert false;
    }
    assert false;
